const crypto = require('crypto');
const SECRET = $env["N8N_WEBHOOK_SECRET"];
const MAX_SKEW_MS = 300000;
const SIG_HEADER = "x-n8n-signature";
const TS_HEADER = "x-n8n-timestamp";
const STATIC_HEADER = "x-static-token";
const hmac = (d) => crypto.createHmac('sha256', SECRET).update(d).digest('hex');
const safeEq = (aHex, bHex) => {
  if (!aHex || !bHex) return false;
  const a = Buffer.from(String(aHex)), b = Buffer.from(String(bHex));
  return a.length === b.length && crypto.timingSafeEqual(a, b);
};
// TE-16: recover the EXACT signed bytes — rawBody when n8n captured it, else a
// careful re-stringify of the parsed body (must round-trip byte-identical).
const rawOf = (j) => (j.rawBody != null) ? j.rawBody.toString() : JSON.stringify(j.body);

const items = $input.all();
for (const it of items) {
  const j = it.json;
  const headers = j.headers || {};
  const raw = rawOf(j);
  let ok = false;
  const sig = headers[SIG_HEADER];
  const ts = headers[TS_HEADER];
  if (ts) {
    // timestamp PRESENT -> studio form: replay-guarded HMAC(`${ts}.${body}`).
    const n = Number(ts);
    if (sig && Number.isFinite(n) && Math.abs(Date.now() - n) <= MAX_SKEW_MS) {
      ok = safeEq(hmac(ts + '.' + raw), sig);
    }
  } else {
    // timestamp ABSENT -> harness verify-n8n form: bare-body HMAC(`${body}`),
    // only the signature header present.
    ok = safeEq(hmac(raw), sig);
  }
  j.__authok = ok;
}
return items;

