const crypto = require('crypto');
const SECRET = $env["N8N_WEBHOOK_SECRET"];
const items = $input.all();
for (const it of items) {
  const j = it.json;
  const requestId = (j.body && j.body.request_id) || j.request_id || null;
  const body = { ok: true, request_id: requestId };
  const payload = JSON.stringify(body);
  j.__body = body;
  j.__ts = String(Date.now());
  j.__sig = crypto.createHmac('sha256', SECRET).update(payload).digest('hex');
}
return items;
